import{_ as o,o as a,c as r,a2 as i}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Arduino","description":"Notes on Arduino.","frontmatter":{"title":"Arduino","description":"Notes on Arduino."},"headers":[],"relativePath":"microcontrollers-and-socs/arduino/k3s-tutorial-arduino.md","filePath":"microcontrollers-and-socs/arduino/k3s-tutorial-arduino.md"}'),t={name:"microcontrollers-and-socs/arduino/k3s-tutorial-arduino.md"};function l(n,e,s,d,u,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="arduino" tabindex="-1">Arduino <a class="header-anchor" href="#arduino" aria-label="Permalink to &quot;Arduino&quot;">​</a></h1><p><strong>DIY Arduino Bluetooth Programming Shield</strong> — wirelessly upload sketches to an Arduino without USB tethering.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://makezine.com/projects/diy-arduino-bluetooth-programming-shield/" target="_blank" rel="noreferrer">Make: DIY Arduino Bluetooth Programming Shield</a></li><li>Published on Make Magazine (project tutorial)</li></ul><h2 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h2><p>An Arduino Uno (or compatible) hosts a <strong>Bluetooth serial module</strong> (e.g. HC-05/HC-06) wired to <code>D0/D1</code> (with optional auto-reset circuit). The IDE connects over a virtual COM port and triggers reset into the bootloader for wireless <code>avrdude</code> uploads.</p><h2 id="typical-wiring-goals" tabindex="-1">Typical wiring goals <a class="header-anchor" href="#typical-wiring-goals" aria-label="Permalink to &quot;Typical wiring goals&quot;">​</a></h2><ul><li>Level-shift Bluetooth module to 5V Arduino logic if needed</li><li>DTR/reset capacitor circuit for auto-reset on serial open</li><li>Power Bluetooth module from regulated 5V or 3.3V per module datasheet</li></ul><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li>Sealed enclosures where USB is inaccessible</li><li>Wearables and installations where the board is buried in a project</li><li>Teaching wireless embedded workflows before moving to ESP32 OTA</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Arduino</a></li><li><a href="./../README.html">MicroControllers &amp; SoCs</a></li></ul>',12)])])}const m=o(t,[["render",l]]);export{p as __pageData,m as default};
